import{_ as a,o as s,c as i,ag as t}from"./chunks/framework.Ca42NP5A.js";const u=JSON.parse('{"title":"Verify on BaseScan","description":"","frontmatter":{},"headers":[],"relativePath":"guides/verify-contracts.md","filePath":"guides/verify-contracts.md","lastUpdated":null}'),n={name:"guides/verify-contracts.md"};function r(o,e,l,c,p,h){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="verify-on-basescan" tabindex="-1">Verify on BaseScan <a class="header-anchor" href="#verify-on-basescan" aria-label="Permalink to &quot;Verify on BaseScan&quot;">​</a></h1><p>Verification uploads your Solidity source to BaseScan, letting anyone read the code and interact with the contract through BaseScan&#39;s Read/Write UI.</p><h2 id="why-verify" tabindex="-1">Why verify <a class="header-anchor" href="#why-verify" aria-label="Permalink to &quot;Why verify&quot;">​</a></h2><p>Verified contracts show:</p><ul><li>Source code, formatted and searchable</li><li><strong>Read Contract</strong> tab — call view functions from the browser, no code needed</li><li><strong>Write Contract</strong> tab — send transactions via MetaMask on BaseScan directly</li><li>Contract ABI publicly exposed for integrations</li></ul><p>For a permissionless civil registry, verification is essentially mandatory — it&#39;s the difference between &quot;public infrastructure&quot; and &quot;opaque addresses.&quot;</p><h2 id="get-an-etherscan-api-key" tabindex="-1">Get an Etherscan API key <a class="header-anchor" href="#get-an-etherscan-api-key" aria-label="Permalink to &quot;Get an Etherscan API key&quot;">​</a></h2><p>The Etherscan V2 API unifies all 60+ chains (Ethereum, Base, Arbitrum, Optimism, etc.) under one key.</p><ol><li>Go to <a href="https://etherscan.io/myapikey" target="_blank" rel="noreferrer">etherscan.io/myapikey</a></li><li>Create a free account and a new API key</li><li>Add to your <code>.env</code>:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ETHERSCAN_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">YourKeyHere</span></span></code></pre></div><h2 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/verify.mjs</span></span></code></pre></div><p>The script reads addresses from <code>deployments.json</code>, compiles each contract with the exact same settings as the deploy (viaIR, optimizer, paris EVM), and submits via Etherscan V2 API.</p><p>Output shows submission → polling → result for each contract:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Verifying AgentRegistry at 0xe8a0...C54...</span></span>
<span class="line"><span>    submitted — GUID: abc123</span></span>
<span class="line"><span>    waiting.</span></span>
<span class="line"><span>    ✓ VERIFIED: https://sepolia.basescan.org/address/0xe8a0...C54#code</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Verifying AgentMemory at 0x3057...0d47...</span></span>
<span class="line"><span>    submitted — GUID: def456</span></span>
<span class="line"><span>    waiting.</span></span>
<span class="line"><span>    ✓ VERIFIED: ...</span></span></code></pre></div><p>Typical time: 15-60 seconds per contract.</p><h2 id="override-addresses" tabindex="-1">Override addresses <a class="header-anchor" href="#override-addresses" aria-label="Permalink to &quot;Override addresses&quot;">​</a></h2><p>Override what&#39;s in <code>deployments.json</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AGENT_REGISTRY_ADDRESS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0x...</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  AGENT_MEMORY_ADDRESS=0x...</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  AGENT_REPUTATION_ADDRESS=0x...</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  CHAIN_ID=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">84532</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/verify.mjs</span></span></code></pre></div><h2 id="compile-settings-must-match-exactly" tabindex="-1">Compile settings must match exactly <a class="header-anchor" href="#compile-settings-must-match-exactly" aria-label="Permalink to &quot;Compile settings must match exactly&quot;">​</a></h2><p>Verification compares the submitted source + compile settings against the deployed bytecode. If they produce different bytes, verification fails with a &quot;bytecode mismatch&quot; error.</p><p>The script uses these settings (matching <code>compile.mjs</code>):</p><ul><li>Compiler: <code>v0.8.24+commit.e11b9ed9</code></li><li><code>viaIR: true</code></li><li>Optimizer: <code>enabled: true, runs: 200</code></li><li>EVM version: <code>paris</code></li></ul><p>If you changed your compile config, update <code>verify.mjs</code> to match, or verify manually on BaseScan.</p><h2 id="manual-verification-fallback" tabindex="-1">Manual verification (fallback) <a class="header-anchor" href="#manual-verification-fallback" aria-label="Permalink to &quot;Manual verification (fallback)&quot;">​</a></h2><p>If the script fails for any reason:</p><ol><li>Go to <a href="https://sepolia.basescan.org/verifyContract" target="_blank" rel="noreferrer">sepolia.basescan.org/verifyContract</a></li><li>Enter the address</li><li>Compiler type: <strong>Solidity (Standard JSON Input)</strong></li><li>Paste the exact JSON that <code>compile.mjs</code> uses (or copy from <code>scripts/verify.mjs</code> — the <code>buildStandardJson</code> function produces it)</li><li>Submit</li></ol><p>For more depth on the V2 API: <a href="https://docs.etherscan.io/etherscan-v2" target="_blank" rel="noreferrer">docs.etherscan.io/etherscan-v2</a>.</p><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li><a href="/docs/reference/contracts">Reference: Contract functions</a> — now that the source is public, here&#39;s what each function does</li></ul>`,30)])])}const y=a(n,[["render",r]]);export{u as __pageData,y as default};
